mapper.select:
SELECT COUNT(id) > 0
FROM user_approval
WHERE approval_id = #{approvalId}
  AND user_id = #{reqUserId}
  AND approval_role = #{requiredRole}
  AND deleted = false

mapper.sql:
WHERE approval.id is not null
AND approval.deleted = #{deleted}
AND approval.step_status LIKE CONCAT('%', #{stepStatus}, '%')
